// src/pages/DashboardHome.js
import React, { useEffect, useState, useCallback, useRef } from 'react';
import Charts from '../components/Charts';
import api from '../services/api';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Fix default Leaflet marker icons
import markerIcon2x from 'leaflet/dist/images/marker-icon-2x.png';
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconUrl: markerIcon,
  iconRetinaUrl: markerIcon2x,
  shadowUrl: markerShadow,
});

const DashboardHome = () => {
  // State Management
  const [vehicleStats, setVehicleStats] = useState({
    total: 4,
    active: 2,
    idle: 1,
    maintenance: 1,
  });
  const [vehicles, setVehicles] = useState([
    { id: 1, lat: 19.0760, lng: 72.8777, status: 'ACTIVE', speed: 45, driver: 'John Doe', fuel: 75 },
    { id: 2, lat: 18.5204, lng: 73.8567, status: 'IDLE', speed: 0, driver: 'Jane Smith', fuel: 90 },
    { id: 3, lat: 12.9716, lng: 77.5946, status: 'MAINTENANCE', speed: 0, driver: 'Mike Johnson', fuel: 60 },
  ]);
  const [alerts, setAlerts] = useState([
    { id: 1, type: 'FUEL_LOW', message: 'Vehicle #24 fuel below 20%', severity: 'HIGH', time: '5 min ago' },
    { id: 2, type: 'MAINTENANCE', message: 'Vehicle #12 scheduled maintenance due', severity: 'MEDIUM', time: '15 min ago' },
    { id: 3, type: 'SPEED_LIMIT', message: 'Vehicle #7 exceeding speed limit', severity: 'HIGH', time: '25 min ago' },
  ]);
  const [loading, setLoading] = useState(false);
  const [currentTime, setCurrentTime] = useState(new Date());

  // Performance metrics
  const [performanceData, setPerformanceData] = useState({
    efficiency: 87,
    fuelConsumption: 145.2,
    totalDistance: 2847,
    avgSpeed: 52,
  });

  // Update time every second
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // Map center calculation
  const mapCenter = vehicles.length > 0
    ? [vehicles[0].lat, vehicles[0].lng]
    : [20.5937, 78.9629];

  // Helper functions
  const getStatusColor = (status) => {
    switch (status) {
      case 'ACTIVE': return 'text-green-600 bg-green-100';
      case 'IDLE': return 'text-yellow-600 bg-yellow-100';
      case 'MAINTENANCE': return 'text-red-600 bg-red-100';
      default: return 'text-gray-600 bg-gray-100';
    }
  };

  const getSeverityColor = (severity) => {
    switch (severity) {
      case 'HIGH': return 'text-red-600 bg-red-100';
      case 'MEDIUM': return 'text-yellow-600 bg-yellow-100';
      case 'LOW': return 'text-green-600 bg-green-100';
      default: return 'text-gray-600 bg-gray-100';
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
      {/* Top Header Bar */}
      <div className="bg-white shadow-sm border-b border-gray-200">
        <div className="px-6 py-4">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">NeuroFleetX Dashboard</h1>
              <p className="text-sm text-gray-600 mt-1">Fleet Management System</p>
            </div>
            <div className="flex items-center space-x-4">
              {/* User Profile */}
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center">
                  <span className="text-white font-semibold text-sm">R</span>
                </div>
                <div className="text-right">
                  <p className="text-sm font-medium text-gray-900">Rakasri</p>
                  <p className="text-xs text-gray-500">Fleet Manager</p>
                </div>
              </div>
              {/* Logout Button */}
              <button className="bg-red-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-red-700 transition-colors flex items-center">
                <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
                </svg>
                Logout
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="p-6">
        
        {/* Dashboard Home Title */}
        <div className="mb-6">
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Dashboard Home</h2>
          <div className="flex items-center text-sm text-gray-600">
            <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
            Last updated: {currentTime.toLocaleTimeString()}
          </div>
        </div>

        {/* Stats Cards - Properly Aligned */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          {/* Total Vehicles */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition-shadow duration-200">
            <div className="flex items-center justify-between">
              <div className="flex-1">
                <p className="text-sm font-medium text-gray-600 mb-2">Total Vehicles</p>
                <p className="text-3xl font-bold text-gray-900">{vehicleStats.total}</p>
                <p className="text-xs text-blue-600 mt-2 flex items-center">
                  <div className="w-2 h-2 bg-blue-500 rounded-full mr-2"></div>
                  Fleet size
                </p>
              </div>
              <div className="w-14 h-14 bg-blue-100 rounded-xl flex items-center justify-center ml-4">
                <svg className="w-7 h-7 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
                </svg>
              </div>
            </div>
          </div>

          {/* Active Vehicles */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition-shadow duration-200">
            <div className="flex items-center justify-between">
              <div className="flex-1">
                <p className="text-sm font-medium text-gray-600 mb-2">Active Vehicles</p>
                <p className="text-3xl font-bold text-gray-900">{vehicleStats.active}</p>
                <p className="text-xs text-green-600 mt-2 flex items-center">
                  <div className="w-2 h-2 bg-green-500 rounded-full mr-2 animate-pulse"></div>
                  Currently moving
                </p>
              </div>
              <div className="w-14 h-14 bg-green-100 rounded-xl flex items-center justify-center ml-4">
                <svg className="w-7 h-7 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
              </div>
            </div>
          </div>

          {/* Idle Vehicles */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition-shadow duration-200">
            <div className="flex items-center justify-between">
              <div className="flex-1">
                <p className="text-sm font-medium text-gray-600 mb-2">Idle Vehicles</p>
                <p className="text-3xl font-bold text-gray-900">{vehicleStats.idle}</p>
                <p className="text-xs text-yellow-600 mt-2 flex items-center">
                  <div className="w-2 h-2 bg-yellow-500 rounded-full mr-2"></div>
                  Ready to deploy
                </p>
              </div>
              <div className="w-14 h-14 bg-yellow-100 rounded-xl flex items-center justify-center ml-4">
                <svg className="w-7 h-7 text-yellow-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                </svg>
              </div>
            </div>
          </div>

          {/* Maintenance */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 hover:shadow-md transition-shadow duration-200">
            <div className="flex items-center justify-between">
              <div className="flex-1">
                <p className="text-sm font-medium text-gray-600 mb-2">Maintenance</p>
                <p className="text-3xl font-bold text-gray-900">{vehicleStats.maintenance}</p>
                <p className="text-xs text-red-600 mt-2 flex items-center">
                  <div className="w-2 h-2 bg-red-500 rounded-full mr-2"></div>
                  Needs attention
                </p>
              </div>
              <div className="w-14 h-14 bg-red-100 rounded-xl flex items-center justify-center ml-4">
                <svg className="w-7 h-7 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.996-.833-2.464 0L3.34 16.5c-.77.833.192 2.5 1.732 2.5z" />
                </svg>
              </div>
            </div>
          </div>
        </div>

        {/* Charts Section - Two Column Layout */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
          
          {/* Vehicle Status Chart */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
            <div className="mb-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-1">Vehicle Status Distribution</h3>
              <p className="text-sm text-gray-600">Current fleet status breakdown</p>
            </div>
            <div className="h-80">
              <Charts
                type="doughnut"
                data={{
                  labels: ['Active', 'Idle', 'Maintenance'],
                  datasets: [
                    {
                      data: [vehicleStats.active, vehicleStats.idle, vehicleStats.maintenance],
                      backgroundColor: ['#10b981', '#f59e0b', '#ef4444'],
                      borderWidth: 0,
                      cutout: '60%',
                    },
                  ],
                }}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  plugins: {
                    legend: {
                      position: 'bottom',
                      labels: {
                        padding: 20,
                        usePointStyle: true,
                        font: { size: 13, weight: '500' },
                      },
                    },
                  },
                }}
              />
            </div>
          </div>

          {/* Fuel Efficiency Chart */}
          <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
            <div className="mb-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-1">Fuel Efficiency</h3>
              <p className="text-sm text-gray-600">Monthly fuel consumption trends</p>
            </div>
            <div className="h-80">
              <Charts
                type="line"
                data={{
                  labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
                  datasets: [
                    {
                      label: 'Fuel Efficiency (km/l)',
                      data: [28.5, 29.2, 27.8, 29.5, 30.1, 28.9],
                      borderColor: '#3b82f6',
                      backgroundColor: 'rgba(59, 130, 246, 0.1)',
                      tension: 0.4,
                      fill: true,
                    },
                  ],
                }}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  plugins: {
                    legend: {
                      display: false,
                    },
                  },
                  scales: {
                    y: {
                      beginAtZero: false,
                      min: 25,
                      max: 32,
                    },
                  },
                }}
              />
            </div>
          </div>
        </div>

        {/* Map Section - Full Width */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100 mb-8">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h3 className="text-lg font-semibold text-gray-900 mb-1">Live Vehicle Tracking</h3>
              <p className="text-sm text-gray-600">Real-time fleet locations</p>
            </div>
            <div className="flex items-center space-x-3">
              <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                <svg className="w-3 h-3 mr-1" fill="currentColor" viewBox="0 0 20 20">
                  <path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" />
                </svg>
                {vehicles.length} vehicles tracked
              </span>
            </div>
          </div>
          <div className="h-96 rounded-lg overflow-hidden border border-gray-200">
            <MapContainer 
              center={mapCenter} 
              zoom={6} 
              className="w-full h-full"
            >
              <TileLayer
                attribution='&copy; <a href="https://www.openstreetmap.org/">OpenStreetMap</a>'
                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
              />
              {vehicles.map(vehicle => (
                <Marker key={vehicle.id} position={[vehicle.lat, vehicle.lng]}>
                  <Popup className="custom-popup">
                    <div className="p-3 min-w-48">
                      <div className="flex items-center mb-3">
                        <div className="w-3 h-3 rounded-full bg-blue-500 mr-2"></div>
                        <strong className="text-gray-900">Vehicle #{vehicle.id}</strong>
                      </div>
                      <div className="space-y-2 text-sm">
                        <div className="flex justify-between items-center">
                          <span className="text-gray-600">Status:</span>
                          <span className={`px-2 py-1 rounded-full text-xs font-medium ${getStatusColor(vehicle.status)}`}>
                            {vehicle.status}
                          </span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-gray-600">Speed:</span>
                          <span className="font-medium">{vehicle.speed} km/h</span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-gray-600">Driver:</span>
                          <span className="font-medium">{vehicle.driver}</span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-gray-600">Fuel:</span>
                          <span className={`font-medium ${vehicle.fuel < 30 ? 'text-red-600' : 'text-green-600'}`}>
                            {vehicle.fuel}%
                          </span>
                        </div>
                      </div>
                    </div>
                  </Popup>
                </Marker>
              ))}
            </MapContainer>
          </div>
        </div>

        {/* Recent Alerts */}
        <div className="bg-white rounded-xl p-6 shadow-sm border border-gray-100">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h3 className="text-lg font-semibold text-gray-900 mb-1">Recent Alerts</h3>
              <p className="text-sm text-gray-600">Latest fleet notifications and warnings</p>
            </div>
            <button className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors">
              View All Alerts
            </button>
          </div>
          <div className="space-y-3">
            {alerts.map(alert => (
              <div key={alert.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-lg border border-gray-100 hover:bg-gray-100 transition-colors">
                <div className="flex items-center flex-1">
                  <div className={`w-10 h-10 rounded-full flex items-center justify-center mr-4 ${getSeverityColor(alert.severity)}`}>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.996-.833-2.464 0L3.34 16.5c-.77.833.192 2.5 1.732 2.5z" />
                    </svg>
                  </div>
                  <div className="flex-1">
                    <p className="font-medium text-gray-900 text-sm">{alert.message}</p>
                    <p className="text-xs text-gray-600 mt-1">{alert.time}</p>
                  </div>
                </div>
                <div className="flex items-center space-x-3">
                  <span className={`px-3 py-1 rounded-full text-xs font-medium ${getSeverityColor(alert.severity)}`}>
                    {alert.severity}
                  </span>
                  <button className="text-gray-400 hover:text-gray-600 transition-colors">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardHome;
